  try {
    // Validate and sanitize query parameters
    if (req.query.id) {
      if (!validator.isInt(req.query.id)) {
        return res.status(400).json({
          error: 'Invalid id parameter',
          message: 'id must be an integer',
        });
      }
      req.query.id = parseInt(req.query.id, 10);
    }

    if (req.query.search) {
      if (!validator.isLength(req.query.search, { min: 1, max: 100 })) {
        return res.status(400).json({
          error: 'Invalid search parameter',
          message: 'search must be between 1 and 100 characters',
        });
      }
      req.query.search = validator.trim(req.query.search);
      req.query.search = validator.escape(req.query.search);
    }

    next();
  } catch (error) {
    res.status(400).json({
      error: 'Input validation failed',
      message: 'Invalid request parameters',
    });
  }
};

