64	function appendLog(line) {
65	  state.logLines.push(line);
66	  if (state.logLines.length > MAX_LOG_LINES) state.logLines.shift();
67	  process.stdout.write(line + "\n");
68	
69	  // Track progress from log output
70	  // Total combinations: "[1/12]" pattern from entrypoint or ">>> N combinations queued"
71	  const totalMatch = line.match(/\[\d+\/(\d+)\]/);
72	  if (totalMatch) state.progress.totalCombinations = parseInt(totalMatch[1], 10);
73	  const queuedMatch = line.match(/>>> (\d+) combinations queued/);
74	  if (queuedMatch) state.progress.totalCombinations = parseInt(queuedMatch[1], 10);
75	
76	  // Combination completed (Test 7: "Completed in", Test 3: "DONE in")
77	  if (/Completed in \d+s/.test(line) || /\] DONE in \d+s/.test(line)) {
78	    state.progress.completedCombinations++;
79	  }
80	  // Combination failed
81	  if (/WARNING: run failed/.test(line) || /\] FAILED:/.test(line)) {
82	    state.progress.completedCombinations++;
83	    state.progress.failedCombinations++;
84	  }
85	
86	  // Individual test result (one per repetition)
87	  if (/^RESULT:/.test(line) || /^\s+RESULT:/.test(line)) {
88	    state.progress.completedRuns++;
89	  }
90	  // Extract GES from result blocks
91	  const gesMatch = line.match(/GES:\s+([\d.]+)/);
92	  if (gesMatch) state.progress.lastGES = parseFloat(gesMatch[1]);
93	}
