95	function startRun(params) {
96	  const env = Object.assign({}, process.env);
97	  const testNum = String(params.test || DEFAULT_TEST);
98	  const entrypoint = ENTRYPOINTS[testNum];
99	  if (!entrypoint) {
100	    throw new Error(`Unknown test number: ${testNum}. Valid: ${Object.keys(ENTRYPOINTS).join(", ")}`);
101	  }
102	
103	  // Test 7 env vars
104	  if (params.models)    env.TEST7_MODELS    = String(params.models);
105	  if (params.scenarios) env.TEST7_SCENARIOS = String(params.scenarios);
106	  if (params.defences)  env.TEST7_DEFENCES  = String(params.defences);
107	  if (params.reps)      env.TEST7_REPS      = String(params.reps);
108	  if (params.runId)     env.TEST7_RUN_ID    = String(params.runId);
109	
110	  // Test 3 env vars
111	  if (params.models)    env.TEST3_MODELS    = String(params.models);
112	  if (params.scenarios) env.TEST3_SCENARIOS = String(params.scenarios);
113	  if (params.defences)  env.TEST3_DEFENCES  = String(params.defences);
114	  if (params.parallel)  env.PARALLEL_JOBS   = String(params.parallel);
115	  if (params.runId)     env.TEST3_RUN_ID    = String(params.runId);
116	
117	  // Test 1 env vars
118	  if (params.effort)    env.TEST1_EFFORT    = String(params.effort);
119	  if (params.config)    env.TEST1_CONFIG    = String(params.config);
120	
121	  // Test 3a env vars
122	  if (params.efforts)   env.TEST3A_EFFORTS  = String(params.efforts);
123	  if (params.reps)      env.TEST3A_REPS     = String(params.reps);
124	  if (params.runId)     env.TEST3A_RUN_ID   = String(params.runId);
125	
126	  // Test 9a env vars
127	  if (params.matrix)    env.TEST9A_MATRIX   = String(params.matrix);
128	  if (params.reps)      env.TEST9A_REPS     = String(params.reps);
129	  if (params.runId)     env.TEST9A_RUN_ID   = String(params.runId);
130	
131	  // Test 8 env vars
132	  if (params.effort)    env.TEST8_EFFORT    = String(params.effort);
133	  if (params.reps)      env.TEST8_REPS      = String(params.reps);
134	  if (params.models)    env.TEST8_MODELS    = String(params.models);
135	
136	  // Test 10/11 env vars
137	  if (params.defences)      env.TEST10_DEFENCES     = String(params.defences);
138	  if (params.model)         env.TEST10_MODEL        = String(params.model);
139	  if (params.effort)        env.TEST10_EFFORT       = String(params.effort);
140	  if (params.judgeEffort)   env.TEST10_JUDGE_EFFORT = String(params.judgeEffort);
141	  if (params.reps)          env.TEST10_REPS         = String(params.reps);
142	
143	  // Shared env vars
144	  if (params.s3Bucket)  env.S3_BUCKET       = String(params.s3Bucket);
145	  if (params.s3Prefix)  env.S3_PREFIX       = String(params.s3Prefix);
146	  if (params.s3Region)  env.S3_REGION       = String(params.s3Region);
147	  if (params.awsRegion) env.AWS_REGION      = String(params.awsRegion);
148	  if (params.bedrockRegion) env.BEDROCK_REGION = String(params.bedrockRegion);
149	
150	  const runId = env.TEST7_RUN_ID || env.TEST3_RUN_ID || new Date().toISOString().replace(/[:.]/g, "");
151	
152	  state = {
153	    status: "running",
154	    runId,
155	    params,
156	    startedAt: new Date().toISOString(),
157	    finishedAt: null,
158	    exitCode: null,
159	    pid: null,
160	    logLines: [],
161	    progress: { ...INITIAL_PROGRESS },
162	  };
163	
164	  const child = spawn(entrypoint, [], {
165	    env,
166	    stdio: ["ignore", "pipe", "pipe"],
167	  });
168	
169	  state.pid = child.pid;
170	  currentProcess = child;
171	
172	  child.stdout.on("data", (data) => {
173	    data.toString().split("\n").filter(Boolean).forEach(appendLog);
174	  });
175	
176	  child.stderr.on("data", (data) => {
177	    data.toString().split("\n").filter(Boolean).forEach((l) => appendLog("[ERR] " + l));
178	  });
179	
180	  child.on("close", (code) => {
181	    state.status = code === 0 ? "done" : "failed";
182	    state.exitCode = code;
183	    state.finishedAt = new Date().toISOString();
184	    currentProcess = null;
185	    console.log(`Run ${runId} finished — exit code ${code}`);
186	  });
187	
188	  child.on("error", (err) => {
189	    state.status = "failed";
190	    state.exitCode = -1;
191	    state.finishedAt = new Date().toISOString();
192	    currentProcess = null;
193	    appendLog("[ERROR] Failed to spawn entrypoint: " + err.message);
194	  });
195	}
